  { d:0, b:false, en:"Holy Hammers: Now has a base radius of 1.8 meters at all gem levels (previously 1.6-1.8 at gem levels 1-20).", pl:"Holy Hammers: Ma teraz base radius 1.8 metra na wszystkich poziomach gemu (poprzednio 1.6–1.8 na poziomach 1–20)." },
  { d:0, b:false, en:"Hydrosphere: Now has a Critical Strike Chance of 6% (previously 5%).", pl:"Hydrosphere: Ma teraz Critical Strike Chance 6% (poprzednio 5%)." },
  { d:0, b:false, en:"Ice Nova: Now has 25% chance to Freeze, and a Critical Strike Chance of 7.5% (previously 6%). Now has 250% Effectiveness of Added Damage at gem level 20 (previously 230%), and now deals 1122 to 1683 Cold Damage at gem level 20 (previously 988 to 1481).", pl:"Ice Nova: Ma teraz 25% chance to Freeze i Critical Strike Chance 7.5% (poprzednio 6%). Ma teraz 250% Effectiveness of Added Damage na poziomie gemu 20 (poprzednio 230%) i zadaje teraz 1122–1683 Cold Damage na poziomie gemu 20 (poprzednio 988–1481)." },
  { d:0, b:false, en:"Ice Nova of Deep Freeze: Now always Freezes (previously 50% chance), and has a Critical Strike Chance of 7.5% (previously 6%). Now has 180% Effectiveness of Added Damage at gem level 20 (previously 140%), and now deals 817 to 1225 Cold Damage at gem level 20 (previously 642 to 963).", pl:"Ice Nova of Deep Freeze: Zawsze teraz Freezes (poprzednio 50% szansy) i ma Critical Strike Chance 7.5% (poprzednio 6%). Ma teraz 180% Effectiveness of Added Damage na poziomie gemu 20 (poprzednio 140%) i zadaje teraz 817–1225 Cold Damage na poziomie gemu 20 (poprzednio 642–963)." },
  { d:0, b:false, en:"Ice Nova of Frostbolts: Now has 25% chance to Freeze, and a Critical Strike Chance of 7.5% (previously 6%).", pl:"Ice Nova of Frostbolts: Ma teraz 25% chance to Freeze i Critical Strike Chance 7.5% (poprzednio 6%)." },
  { d:0, b:false, en:"Ice Spear: Now has a Critical Strike Chance of 7.5% (previously 7%).", pl:"Ice Spear: Ma teraz Critical Strike Chance 7.5% (poprzednio 7%)." },
  { d:0, b:false, en:"Ice Spear of Splitting: Now has a Critical Strike Chance of 7.5% (previously 5%), and Projectiles now Split towards 4-7 targets at gem levels 1-20 (previously 2-5).", pl:"Ice Spear of Splitting: Ma teraz Critical Strike Chance 7.5% (poprzednio 5%), a Projectiles rozdzielają się teraz w kierunku 4–7 celów na poziomach gemu 1–20 (poprzednio 2–5)." },
  { d:0, b:false, en:"Icestorm, granted by the Whispering Ice Unique Staff: Now has a maximum of 8 Icestorms (previously 5).", pl:"Icestorm, nadawane przez unikatowy kostur Whispering Ice: Ma teraz maksymalnie 8 Icestorms (poprzednio 5)." }
